  3→import { useState, useRef, useEffect, useCallback } from "react";
  4→import { useRouter, usePathname } from "next/navigation";
  5→import ReactMarkdown from "react-markdown";
  6→
  7→interface Message {
  8→  role: "user" | "assistant";
  9→  content: string;
 10→  navStatus?: "pending" | "done";
 11→  navRoute?: string;
 12→}
 13→
 14→const STORAGE_KEY = "ck-chat-messages";
 15→
 16→const GREETING: Message = {
 17→  role: "assistant",
 18→  content:
 19→    "Hey! I'm **Cam Code**, Cameron's AI assistant. Ask me anything or type `/help` to see available commands.",
 20→};
 21→
 22→// ── Slash commands ───────────────────────────────────────────────────
 23→type CommandAction = "navigate" | "resume" | "clear" | "help" | "skills" | "socials" | "whoami" | "stats" | "source" | "email";
 24→
 25→const SLASH_COMMANDS: Record<string, { description: string; action: CommandAction }> = {
 26→  "/help": { description: "Show available commands", action: "help" },
 27→  "/skills": { description: "View Cameron's technical skills", action: "skills" },
 28→  "/socials": { description: "GitHub, LinkedIn, X links", action: "socials" },
 29→  "/whoami": { description: "Quick bio", action: "whoami" },
 30→  "/stats": { description: "Golf highlights", action: "stats" },
 31→  "/email": { description: "Get Cameron's email", action: "email" },
 32→  "/source": { description: "View site source code", action: "source" },
 33→  "/resume": { description: "Open Cameron's resume", action: "resume" },
 34→  "/clear": { description: "Clear conversation", action: "clear" },
 35→  "/home": { description: "Go to home page", action: "navigate" },
 36→  "/about": { description: "Go to about page", action: "navigate" },
 37→  "/work": { description: "Go to work & experience", action: "navigate" },
 38→  "/projects": { description: "Go to projects", action: "navigate" },
 39→  "/golf": { description: "Go to golf page", action: "navigate" },
 40→  "/blog": { description: "Go to blog", action: "navigate" },
 41→  "/contact": { description: "Go to contact page", action: "navigate" },
 42→};
 43→
 44→function buildSkillsText(): string {
