 52→    "**Fundamentals** - Data Structures, OOP, Linear Algebra, Hidden Markov Models",
 53→    "**Business** - Entrepreneurship, Startup Development, Business Strategy, Team Leadership",
 54→  ].join("\n");
 55→}
