 72→}
 73→
 74→function buildStatsText(): string {
 75→  return [
 76→    "**Golf Highlights**",
 77→    "- NCAA D1 Varsity Golf, Dartmouth (2022-Present)",
 78→    "- Cornell vs. Dartmouth Stroke Play: Individual Winner (2024)",
