 81→    "- Junior Olympian of the Year (2021)",
 82→    "- 130+ junior tournament entries (2016-2021)",
 83→  ].join("\n");
 84→}
 85→
 86→const ROUTE_MAP: Record<string, string> = {
 87→  "/home": "/",
 88→  "/about": "/about",
 89→  "/work": "/work",
 90→  "/projects": "/projects",
 91→  "/golf": "/golf",
