 96→function buildHelpText(): string {
 97→  const lines = Object.entries(SLASH_COMMANDS).map(
 98→    ([cmd, { description }]) => `\`${cmd}\` - ${description}`
 99→  );
100→  return `**Available commands:**\n${lines.join("\n")}`;
101→}
102→
103→function loadMessages(): Message[] {
104→  if (typeof window === "undefined") return [GREETING];
105→  try {
106→    const stored = localStorage.getItem(STORAGE_KEY);
107→    if (stored) {
108→      const parsed = JSON.parse(stored) as Message[];
109→      if (parsed.length > 0) return parsed;
110→    }
111→  } catch {
112→    // Corrupted storage - reset
113→  }
114→  return [GREETING];
115→}
116→
117→// ── Cam Code sparkle icon (Claude-inspired) ──────────────────────────
118→function CamCodeIcon({
119→  size = 20,
120→  className,
121→}: {
122→  size?: number;
123→  className?: string;
124→}) {
125→  return (
126→    <svg
