170→
171→export function ChatWidget() {
172→  const [isOpen, setIsOpen] = useState(false);
173→  const [messages, setMessages] = useState<Message[]>([GREETING]);
174→  const [input, setInput] = useState("");
175→  const [isLoading, setIsLoading] = useState(false);
176→  const [inputFocused, setInputFocused] = useState(false);
177→  const messagesEndRef = useRef<HTMLDivElement>(null);
178→  const inputRef = useRef<HTMLInputElement>(null);
179→  const router = useRouter();
180→  const pathname = usePathname();
181→  const isHomepage = pathname === "/";
182→
183→  // Load conversation from localStorage on mount
184→  useEffect(() => {
185→    setMessages(loadMessages());
186→  }, []);
187→
188→  // Persist conversation to localStorage whenever messages change
189→  useEffect(() => {
190→    try {
191→      localStorage.setItem(STORAGE_KEY, JSON.stringify(messages.slice(-50)));
192→    } catch {
193→      // Storage full or unavailable
194→    }
195→  }, [messages]);
196→
197→  // Auto-scroll to bottom when messages change
198→  useEffect(() => {
199→    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
200→  }, [messages]);
201→
202→  // Focus input when chat opens
203→  useEffect(() => {
204→    if (isOpen) {
205→      setTimeout(() => inputRef.current?.focus(), 150);
206→    }
207→  }, [isOpen]);
208→
209→  // Keyboard shortcut: Cmd/Ctrl + K to toggle
210→  useEffect(() => {
211→    function handleKeyDown(e: KeyboardEvent) {
212→      if ((e.metaKey || e.ctrlKey) && e.key === "k") {
213→        e.preventDefault();
214→        setIsOpen((prev) => !prev);
215→      }
216→    }
217→    window.addEventListener("keydown", handleKeyDown);
218→    return () => window.removeEventListener("keydown", handleKeyDown);
219→  }, []);
220→
221→  // ── Handle slash commands ──────────────────────────────────────────
222→  const handleSlashCommand = useCallback(
223→    (cmd: string): boolean => {
224→      const normalized = cmd.toLowerCase().trim();
225→      const command = SLASH_COMMANDS[normalized];
226→      if (!command) return false;
227→
228→      // Show the command as a user message
229→      setMessages((prev) => [...prev, { role: "user", content: normalized }]);
230→
231→      switch (command.action) {
232→        case "help":
233→          setMessages((prev) => [
234→            ...prev,
235→            { role: "assistant", content: buildHelpText() },
236→          ]);
237→          break;
238→
239→        case "clear":
240→          setMessages([GREETING]);
241→          localStorage.removeItem(STORAGE_KEY);
242→          break;
243→
244→        case "navigate": {
245→          const route = ROUTE_MAP[normalized];
246→          if (route) {
247→            setMessages((prev) => [
248→              ...prev,
249→              { role: "assistant", content: "", navStatus: "pending", navRoute: route },
250→            ]);
251→            router.push(route);
252→            setTimeout(() => {
253→              setMessages((prev) => {
254→                const updated = [...prev];
255→                for (let i = updated.length - 1; i >= 0; i--) {
256→                  if (updated[i].navStatus === "pending" && updated[i].navRoute === route) {
257→                    updated[i] = { ...updated[i], navStatus: "done" };
258→                    break;
259→                  }
260→                }
261→                return updated;
262→              });
263→            }, 700);
264→          }
265→          break;
266→        }
267→
268→        case "resume":
269→          window.open("/cameron-keith-resume.pdf", "_blank");
270→          setMessages((prev) => [
271→            ...prev,
272→            {
273→              role: "assistant",
274→              content: "Opening **Cameron's resume** in a new tab.",
275→            },
276→          ]);
277→          break;
278→
279→        case "skills":
280→          setMessages((prev) => [
281→            ...prev,
282→            { role: "assistant", content: buildSkillsText() },
283→          ]);
284→          break;
285→
286→        case "socials":
287→          setMessages((prev) => [
288→            ...prev,
289→            { role: "assistant", content: buildSocialsText() },
290→          ]);
291→          break;
292→
293→        case "whoami":
294→          setMessages((prev) => [
295→            ...prev,
296→            { role: "assistant", content: buildWhoamiText() },
297→          ]);
298→          break;
299→
300→        case "stats":
301→          setMessages((prev) => [
302→            ...prev,
303→            { role: "assistant", content: buildStatsText() },
304→          ]);
305→          break;
306→
307→        case "email":
308→          setMessages((prev) => [
309→            ...prev,
310→            { role: "assistant", content: "**cameron.s.keith.26@dartmouth.edu**" },
311→          ]);
312→          break;
313→
314→        case "source":
315→          window.open("https://github.com/ckeith26/cameronkeithgolf", "_blank");
316→          setMessages((prev) => [
317→            ...prev,
318→            { role: "assistant", content: "Opening **source repo** in a new tab." },
319→          ]);
320→          break;
321→      }
322→
323→      return true;
324→    },
325→    [router]
326→  );
327→
328→  // ── Send message (AI or slash command) ─────────────────────────────
329→  const sendMessage = useCallback(async () => {
330→    const trimmed = input.trim();
331→    if (!trimmed || isLoading) return;
332→    setInput("");
333→
334→    // Check for slash commands first
335→    if (trimmed.startsWith("/")) {
336→      if (handleSlashCommand(trimmed)) return;
337→      // Unknown command - show help
338→      setMessages((prev) => [
339→        ...prev,
340→        { role: "user", content: trimmed },
341→        {
342→          role: "assistant",
343→          content: `Unknown command \`${trimmed}\`. Type \`/help\` to see available commands.`,
344→        },
345→      ]);
346→      return;
347→    }
348→
349→    // Regular AI message
350→    const userMessage: Message = { role: "user", content: trimmed };
351→    const updatedMessages = [...messages, userMessage];
352→    setMessages(updatedMessages);
353→    setIsLoading(true);
354→
355→    // Add empty assistant message as placeholder for streaming
356→    setMessages((prev) => [...prev, { role: "assistant", content: "" }]);
357→
358→    try {
359→      const response = await fetch("/api/agent", {
360→        method: "POST",
361→        headers: { "Content-Type": "application/json" },
362→        body: JSON.stringify({
363→          messages: updatedMessages.slice(-50).map((m) => ({
364→            role: m.role,
365→            content: m.content,
366→          })),
367→        }),
368→      });
369→
370→      if (!response.ok) throw new Error("Request failed");
371→
372→      const reader = response.body!.getReader();
373→      const decoder = new TextDecoder();
374→      let buffer = "";
375→
376→      while (true) {
377→        const { done, value } = await reader.read();
378→        if (done) break;
379→
380→        buffer += decoder.decode(value, { stream: true });
381→        const lines = buffer.split("\n");
382→        buffer = lines.pop() || "";
383→
384→        for (const line of lines) {
385→          if (!line.trim()) continue;
386→          try {
387→            const event = JSON.parse(line);
388→            if (event.type === "text") {
389→              setMessages((prev) => {
390→                const updated = [...prev];
391→                const last = updated[updated.length - 1];
392→                if (last.role === "assistant") {
393→                  updated[updated.length - 1] = {
394→                    ...last,
395→                    content: last.content + event.content,
396→                  };
397→                }
398→                return updated;
399→              });
400→            } else if (event.type === "navigate") {
401→              setMessages((prev) => [
402→                ...prev,
403→                { role: "assistant", content: "", navStatus: "pending", navRoute: event.route },
404→              ]);
405→              router.push(event.route);
406→              setTimeout(() => {
407→                setMessages((prev) => {
408→                  const updated = [...prev];
409→                  for (let i = updated.length - 1; i >= 0; i--) {
410→                    if (updated[i].navStatus === "pending") {
411→                      updated[i] = { ...updated[i], navStatus: "done" };
412→                      break;
413→                    }
414→                  }
415→                  return updated;
416→                });
417→              }, 700);
418→            } else if (event.type === "open_resume") {
419→              window.open(event.url, "_blank");
420→            } else if (event.type === "error") {
421→              setMessages((prev) => {
422→                const updated = [...prev];
423→                const last = updated[updated.length - 1];
424→                if (last.role === "assistant" && !last.content) {
425→                  updated[updated.length - 1] = {
426→                    ...last,
427→                    content: event.message,
428→                  };
429→                }
430→                return updated;
431→              });
432→            }
433→          } catch {
434→            // Skip malformed lines
435→          }
436→        }
437→      }
