444→            ...last,
445→            content: "Sorry, something went wrong. Please try again.",
446→          };
447→        }
448→        return updated;
449→      });
450→    } finally {
451→      setIsLoading(false);
452→    }
453→  }, [input, isLoading, messages, router, handleSlashCommand]);
454→
455→  if (isHomepage) return null;
456→
457→  return (
458→    <>
