501→                  camkeith.me
502→                </p>
503→              </div>
504→            </div>
505→          </div>
506→
507→          {/* Messages */}
508→          <div className="flex-1 overflow-y-auto px-4 py-3 space-y-3 min-h-[200px] max-h-[380px]">
509→            {messages.map((msg, i) =>
