187→      return (
188→        <Link href={href} className="text-[#10b981] underline hover:text-[#34d399]">
189→          {children}
190→        </Link>
191→      );
192→    }
193→    return (
194→      <a
195→        href={href}
196→        className="text-[#10b981] underline hover:text-[#34d399]"
197→        target="_blank"
198→        rel="noopener noreferrer"
