206→// ── Line Renderers ───────────────────────────────────────────────────
207→
208→function renderTextLine(line: Extract<TerminalLine, { type: "text" }>) {
209→  const { content, style } = line;
210→
211→  if (!content) return <span className="inline-block h-4">{"\u00A0"}</span>;
212→
213→  switch (style) {
214→    case "command":
215→      if (content.startsWith("❯ ")) {
216→        const cmd = content.slice(2);
217→        const isSlashCommand = cmd.startsWith("/") && cmd.toLowerCase().trim() in SLASH_COMMANDS;
218→        return (
219→          <span className="leading-relaxed">
220→            <span className="text-[#10b981]">❯ </span>
221→            <span className={isSlashCommand ? "text-[#10b981]" : "text-[#fafafa]"}>{cmd}</span>
222→          </span>
223→        );
224→      }
225→      if (content.startsWith("$ ")) {
226→        return (
227→          <span className="leading-relaxed">
228→            <span className="text-[#10b981]">$ </span>
229→            <span className="text-[#fafafa]">{content.slice(2)}</span>
230→          </span>
231→        );
232→      }
233→      return <span className="leading-relaxed text-[#10b981]">{content}</span>;
234→
235→    case "muted":
236→      return <span className="leading-relaxed text-[#71717a]">{content}</span>;
237→
238→    case "success":
239→      if (content.startsWith("✓")) {
240→        return (
241→          <span className="leading-relaxed">
242→            <span className="text-[#10b981]">✓</span>
243→            <span className="text-[#e4e4e7]">{content.slice(1)}</span>
244→          </span>
245→        );
246→      }
247→      return <span className="leading-relaxed text-[#10b981]">{content}</span>;
248→
249→    case "greeting":
250→      return <span className="leading-relaxed text-[#e4e4e7]">{content}</span>;
251→
252→    default:
253→      return <span className="leading-relaxed text-[#a1a1aa]">{content}</span>;
254→  }
255→}
