257→function renderAiLine(line: Extract<TerminalLine, { type: "ai" }>) {
258→  if (!line.content) return null;
259→  return (
260→    <div className="leading-relaxed pl-1 border-l-2 border-[#27272a] ml-1 my-1">
261→      <ReactMarkdown components={markdownComponents}>{line.content}</ReactMarkdown>
262→    </div>
