266→function renderNavLine(line: Extract<TerminalLine, { type: "nav" }>) {
267→  return (
268→    <div className="flex items-center gap-2 leading-relaxed">
269→      {line.status === "pending" ? (
270→        <svg
271→          className="w-3.5 h-3.5 text-[#10b981] animate-spin shrink-0"
272→          viewBox="0 0 24 24"
273→          fill="none"
274→        >
275→          <circle cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="3" opacity="0.25" />
276→          <path d="M12 2a10 10 0 0 1 10 10" stroke="currentColor" strokeWidth="3" strokeLinecap="round" />
277→        </svg>
