369→
370→export function Terminal({ className }: TerminalProps) {
371→  const containerRef = useRef<HTMLDivElement>(null);
372→  const outputRef = useRef<HTMLDivElement>(null);
373→  const inputRef = useRef<HTMLInputElement>(null);
374→
375→  const [lines, setLines] = useState<TerminalLine[]>([]);
376→  const [messages, setMessages] = useState<Message[]>([]);
377→  const [isTyping, setIsTyping] = useState(false);
378→  const [bootComplete, setBootComplete] = useState(false);
379→  const [inputValue, setInputValue] = useState("");
380→  const [isLoading, setIsLoading] = useState(false);
381→
382→  const hasBootedRef = useRef(false);
383→
384→  const mountedRef = useRef(true);
385→
386→  const prefersReducedMotion = useReducedMotion();
387→  const router = useRouter();
388→
389→  useEffect(() => {
390→    return () => { mountedRef.current = false; };
391→  }, []);
392→
393→  // ── Scroll to bottom ───────────────────────────────────────────────
394→
395→  const scrollToBottom = useCallback(() => {
396→    if (outputRef.current) {
397→      outputRef.current.scrollTop = outputRef.current.scrollHeight;
398→    }
399→  }, []);
400→
401→  // ── Auto-scroll whenever lines change ──────────────────────────────
402→
403→  useEffect(() => {
404→    scrollToBottom();
405→  }, [lines, scrollToBottom]);
406→
407→  // ── Typewriter utility ─────────────────────────────────────────────
408→
409→  const typeText = useCallback(
410→    (text: string, style?: "command" | "muted" | "success" | "greeting"): Promise<void> => {
411→      return new Promise((resolve) => {
412→        if (!text) {
413→          setLines((prev) => [...prev, { type: "text", content: "", style }]);
414→          resolve();
415→          return;
416→        }
417→
418→        let currentIndex = 0;
419→        // Push an empty text line that we'll fill character by character
420→        setLines((prev) => [...prev, { type: "text", content: "", style }]);
421→
422→        function typeNextChar() {
423→          if (!mountedRef.current) { resolve(); return; }
424→          if (currentIndex < text.length) {
425→            currentIndex++;
426→            setLines((prev) => {
427→              const updated = [...prev];
428→              const last = updated[updated.length - 1];
429→              if (last.type === "text") {
430→                updated[updated.length - 1] = { ...last, content: text.slice(0, currentIndex) };
431→              }
432→              return updated;
433→            });
434→            scrollToBottom();
435→            const delay = 15 + Math.random() * 15;
436→            setTimeout(typeNextChar, delay);
437→          } else {
438→            resolve();
439→          }
440→        }
441→
442→        typeNextChar();
443→      });
444→    },
445→    [scrollToBottom]
446→  );
447→
448→  // ── Boot sequence ──────────────────────────────────────────────────
449→
450→  const playBoot = useCallback(async () => {
451→    if (prefersReducedMotion) {
452→      setLines([
453→        { type: "text", content: "$ cam", style: "command" },
454→        { type: "welcome" },
455→        ...BOOT_LINES.map((b) => ({ type: "text" as const, content: b.content, style: b.style })),
456→      ]);
457→      setBootComplete(true);
458→      return;
459→    }
460→
461→    setIsTyping(true);
462→
463→    // Type "cam" at the shell prompt character by character
464→    const command = "cam";
465→    setLines([{ type: "text", content: "$ ", style: "command" }]);
466→    for (let i = 0; i < command.length; i++) {
467→      await new Promise((r) => setTimeout(r, 60 + Math.random() * 40));
468→      setLines([{ type: "text", content: `$ ${command.slice(0, i + 1)}`, style: "command" }]);
469→    }
470→    await new Promise((r) => setTimeout(r, 300));
471→
472→    // Show welcome box
473→    setLines((prev) => [...prev, { type: "welcome" }]);
474→    await new Promise((r) => setTimeout(r, 400));
475→
476→    // Boot sequence
477→    for (const bootLine of BOOT_LINES) {
478→      await typeText(bootLine.content, bootLine.style);
479→      await new Promise((r) => setTimeout(r, bootLine.delay));
480→    }
481→
482→    setIsTyping(false);
483→    setBootComplete(true);
484→  }, [prefersReducedMotion, typeText]);
485→
486→  // ── Persist messages on every change ───────────────────────────────
487→
488→  useEffect(() => {
489→    if (messages.length > 0) {
490→      persistMessages(messages);
491→    }
492→  }, [messages]);
493→
494→  // ── IntersectionObserver: auto-boot when scrolled into view ────────
495→
496→  useEffect(() => {
497→    const container = containerRef.current;
498→    if (!container || hasBootedRef.current) return;
499→
500→    const observer = new IntersectionObserver(
501→      (entries) => {
502→        if (entries[0].isIntersecting && !hasBootedRef.current) {
503→          hasBootedRef.current = true;
504→          observer.disconnect();
505→
506→          const stored = loadMessages();
507→          if (stored && stored.length > 0) {
508→            setMessages(stored);
509→            setLines([
510→              { type: "text", content: "$ cam", style: "command" },
511→              { type: "welcome" },
512→              ...messagesToLines(stored),
513→            ]);
514→            setBootComplete(true);
515→          } else {
516→            playBoot();
517→          }
518→        }
519→      },
520→      { threshold: 0.5 }
521→    );
522→
523→    observer.observe(container);
524→    return () => observer.disconnect();
525→  }, [playBoot]);
526→
527→  // ── Focus input when boot completes ────────────────────────────────
528→
529→  useEffect(() => {
530→    if (bootComplete) {
531→      scrollToBottom();
532→      setTimeout(() => inputRef.current?.focus(), 100);
533→    }
534→  }, [bootComplete, scrollToBottom]);
535→
536→  // ── Global keyboard capture: focus terminal on any typing ──────────
537→
538→  useEffect(() => {
539→    if (!bootComplete) return;
540→
541→    function handleGlobalKeydown(e: KeyboardEvent) {
542→      // Ignore if user is focused on another input/textarea
543→      const tag = (e.target as HTMLElement)?.tagName;
544→      if (tag === "INPUT" || tag === "TEXTAREA" || (e.target as HTMLElement)?.isContentEditable) return;
545→
546→      // Ignore modifier-only keys and special keys
547→      if (e.metaKey || e.ctrlKey || e.altKey) return;
548→      if (e.key.length > 1 && e.key !== "Backspace") return;
549→
550→      inputRef.current?.focus();
551→    }
552→
553→    window.addEventListener("keydown", handleGlobalKeydown);
554→    return () => window.removeEventListener("keydown", handleGlobalKeydown);
555→  }, [bootComplete]);
556→
557→  // ── Slash command handler ──────────────────────────────────────────
558→
559→  const handleSlashCommand = useCallback(
560→    (cmd: string): boolean => {
561→      const normalized = cmd.toLowerCase().trim();
562→      const command = SLASH_COMMANDS[normalized];
563→      if (!command) return false;
564→
565→      // Show the command as a terminal line
566→      setLines((prev) => [...prev, { type: "text", content: `❯ ${normalized}`, style: "command" }]);
567→
568→      // Also track in messages for AI context
569→      const userMsg: Message = { role: "user", content: normalized };
570→
571→      switch (command.action) {
572→        case "help": {
573→          const helpLines = buildHelpLines();
574→          setLines((prev) => [...prev, ...helpLines]);
575→          const helpContent = Object.entries(SLASH_COMMANDS)
576→            .map(([c, { description }]) => `${c} - ${description}`)
577→            .join("\n");
578→          setMessages((prev) => [...prev, userMsg, { role: "assistant", content: helpContent }]);
579→          break;
580→        }
581→
582→        case "clear":
583→          setLines([
584→            { type: "text", content: "$ cam", style: "command" },
585→            { type: "welcome" },
586→          ]);
587→          setMessages([]);
588→          localStorage.removeItem(STORAGE_KEY);
589→          break;
590→
591→        case "navigate": {
592→          const route = ROUTE_MAP[normalized];
593→          if (route) {
594→            setLines((prev) => [...prev, { type: "nav", status: "pending", route }]);
595→            setMessages((prev) => [...prev, userMsg, { role: "assistant", content: `Navigating to ${route}` }]);
596→            router.push(route);
597→            setTimeout(() => {
598→              setLines((prev) => {
599→                const updated = [...prev];
600→                for (let i = updated.length - 1; i >= 0; i--) {
601→                  const line = updated[i];
602→                  if (line.type === "nav" && line.status === "pending" && line.route === route) {
603→                    updated[i] = { ...line, status: "done" };
604→                    break;
605→                  }
606→                }
607→                return updated;
608→              });
609→            }, 700);
610→          }
611→          break;
612→        }
613→
614→        case "resume":
615→          window.open("/cameron-keith-resume.pdf", "_blank");
616→          setLines((prev) => [
617→            ...prev,
618→            { type: "text", content: "Opening Cameron's resume in a new tab.", style: "success" },
619→          ]);
620→          setMessages((prev) => [
621→            ...prev,
622→            userMsg,
623→            { role: "assistant", content: "Opening Cameron's resume in a new tab." },
624→          ]);
625→          break;
626→
627→        case "skills": {
628→          const skillsLines = buildSkillsLines();
629→          setLines((prev) => [...prev, ...skillsLines]);
630→          setMessages((prev) => [...prev, userMsg, { role: "assistant", content: "/skills" }]);
631→          break;
632→        }
633→
634→        case "socials": {
635→          const socialsLines = buildSocialsLines();
636→          setLines((prev) => [...prev, ...socialsLines]);
637→          setMessages((prev) => [...prev, userMsg, { role: "assistant", content: "/socials" }]);
638→          break;
639→        }
640→
641→        case "whoami": {
642→          const whoamiLines = buildWhoamiLines();
643→          setLines((prev) => [...prev, ...whoamiLines]);
644→          setMessages((prev) => [...prev, userMsg, { role: "assistant", content: "/whoami" }]);
645→          break;
646→        }
647→
648→        case "stats": {
649→          const statsLines = buildStatsLines();
650→          setLines((prev) => [...prev, ...statsLines]);
651→          setMessages((prev) => [...prev, userMsg, { role: "assistant", content: "/stats" }]);
652→          break;
653→        }
654→
655→        case "email":
656→          setLines((prev) => [
657→            ...prev,
658→            { type: "text", content: "  cameron.s.keith.26@dartmouth.edu", style: "muted" },
659→          ]);
660→          setMessages((prev) => [...prev, userMsg, { role: "assistant", content: "cameron.s.keith.26@dartmouth.edu" }]);
661→          break;
662→
663→        case "source":
664→          window.open("https://github.com/ckeith26/cameronkeithgolf", "_blank");
665→          setLines((prev) => [
666→            ...prev,
667→            { type: "text", content: "Opening source repo in a new tab.", style: "success" },
668→          ]);
669→          setMessages((prev) => [...prev, userMsg, { role: "assistant", content: "Opening source repo." }]);
670→          break;
671→      }
672→
673→      return true;
674→    },
675→    [router]
676→  );
677→
678→  // ── Send AI message ────────────────────────────────────────────────
679→
680→  const sendMessage = useCallback(
681→    async (text: string) => {
682→      const trimmed = text.trim();
683→      if (!trimmed || isLoading) return;
684→
685→      // Check for slash commands first
686→      if (trimmed.startsWith("/")) {
687→        if (handleSlashCommand(trimmed)) return;
688→        // Unknown slash command
689→        setLines((prev) => [
690→          ...prev,
691→          { type: "text", content: `❯ ${trimmed}`, style: "command" },
692→          { type: "text", content: `Unknown command "${trimmed}". Type /help to see available commands.`, style: "muted" },
693→        ]);
694→        return;
695→      }
696→
697→      // Show user input as command line
698→      setLines((prev) => [...prev, { type: "text", content: `❯ ${trimmed}`, style: "command" }]);
699→
700→      // Build messages for API - use functional updater to avoid stale closure
701→      const userMsg: Message = { role: "user", content: trimmed };
702→      let updatedMessages: Message[] = [];
703→      setMessages((prev) => {
704→        updatedMessages = [...prev, userMsg];
705→        return updatedMessages;
706→      });
707→
708→      // Show loading indicator
709→      setIsLoading(true);
710→      setLines((prev) => [...prev, { type: "loading" }]);
711→
712→      try {
713→        const response = await fetch("/api/agent", {
714→          method: "POST",
715→          headers: { "Content-Type": "application/json" },
716→          body: JSON.stringify({
717→            messages: updatedMessages.slice(-50).map((m) => ({
718→              role: m.role,
719→              content: m.content,
720→            })),
721→          }),
722→        });
723→
724→        if (!response.ok) throw new Error("Request failed");
725→
726→        // Remove loading indicator and add empty AI line for streaming
727→        setLines((prev) => {
728→          const filtered = prev.filter((l) => l.type !== "loading");
729→          return [...filtered, { type: "ai", content: "" }];
730→        });
731→
732→        if (!response.body) throw new Error("No response stream");
733→        const reader = response.body.getReader();
734→        const decoder = new TextDecoder();
735→        let buffer = "";
736→        let accumulatedContent = "";
737→
738→        while (true) {
739→          const { done, value } = await reader.read();
740→          if (done) break;
741→
742→          buffer += decoder.decode(value, { stream: true });
743→          const jsonLines = buffer.split("\n");
744→          buffer = jsonLines.pop() || "";
745→
746→          for (const jsonLine of jsonLines) {
747→            if (!jsonLine.trim()) continue;
748→            try {
749→              const event = JSON.parse(jsonLine);
750→
751→              if (event.type === "text") {
752→                accumulatedContent += event.content;
753→                setLines((prev) => {
754→                  const updated = [...prev];
755→                  // Find the last AI line to update
756→                  for (let i = updated.length - 1; i >= 0; i--) {
757→                    if (updated[i].type === "ai") {
758→                      updated[i] = { type: "ai", content: accumulatedContent };
759→                      break;
760→                    }
761→                  }
762→                  return updated;
763→                });
764→                scrollToBottom();
765→              } else if (event.type === "navigate") {
766→                setLines((prev) => [
767→                  ...prev,
768→                  { type: "nav", status: "pending", route: event.route },
769→                ]);
770→                router.push(event.route);
771→                setTimeout(() => {
772→                  setLines((prev) => {
773→                    const updated = [...prev];
774→                    for (let i = updated.length - 1; i >= 0; i--) {
775→                      const line = updated[i];
776→                      if (line.type === "nav" && line.status === "pending") {
777→                        updated[i] = { ...line, status: "done" };
778→                        break;
779→                      }
780→                    }
781→                    return updated;
782→                  });
783→                }, 700);
784→              } else if (event.type === "open_resume") {
785→                window.open(event.url, "_blank");
786→              } else if (event.type === "error") {
787→                setLines((prev) => {
788→                  const updated = [...prev];
789→                  for (let i = updated.length - 1; i >= 0; i--) {
790→                    if (updated[i].type === "ai" && (updated[i] as Extract<TerminalLine, { type: "ai" }>).content === "") {
791→                      updated[i] = { type: "ai", content: event.message };
792→                      break;
793→                    }
794→                  }
795→                  return updated;
796→                });
797→              }
798→            } catch {
799→              // Skip malformed JSON lines
800→            }
801→          }
802→        }
803→
804→        // Store the assistant response in messages
805→        if (accumulatedContent) {
806→          setMessages((prev) => [...prev, { role: "assistant", content: accumulatedContent }]);
807→        }
808→      } catch {
809→        // Remove loading indicator and show error
810→        setLines((prev) => {
811→          const filtered = prev.filter((l) => l.type !== "loading");
812→          // Check if there's an empty AI line to replace
813→          const lastIdx = filtered.length - 1;
814→          if (lastIdx >= 0 && filtered[lastIdx].type === "ai" && (filtered[lastIdx] as Extract<TerminalLine, { type: "ai" }>).content === "") {
815→            const updated = [...filtered];
816→            updated[lastIdx] = { type: "ai", content: "Sorry, something went wrong. Please try again." };
817→            return updated;
818→          }
819→          return [...filtered, { type: "ai", content: "Sorry, something went wrong. Please try again." }];
820→        });
821→        setMessages((prev) => [
822→          ...prev,
823→          { role: "assistant", content: "Sorry, something went wrong. Please try again." },
824→        ]);
825→      } finally {
826→        setIsLoading(false);
827→      }
828→    },
829→    [isLoading, router, handleSlashCommand, scrollToBottom]
830→  );
831→
832→  // ── Handle submit ──────────────────────────────────────────────────
833→
834→  const handleSubmit = useCallback(() => {
835→    if (!inputValue.trim()) return;
836→    const val = inputValue;
837→    setInputValue("");
838→    sendMessage(val);
839→  }, [inputValue, sendMessage]);
840→
841→  // ── Render ─────────────────────────────────────────────────────────
842→
843→  const boxLine = "─".repeat(120);
844→
845→  return (
846→    <div
847→      ref={containerRef}
848→      className={`bg-[#111111] font-mono rounded-lg border border-[#27272a] flex flex-col ${className ?? ""}`}
849→    >
850→      {/* Title bar */}
851→      <div className="flex items-center justify-center px-4 py-3 border-b border-[#27272a]">
852→        <span className="text-[#71717a] text-xs">✻ Cam Code - v1.0 ‹ terminal</span>
853→      </div>
854→
855→      {/* Output area */}
856→      <div
857→        ref={outputRef}
858→        className="flex-1 p-4 text-sm min-h-[200px] max-h-[400px] overflow-y-auto"
859→      >
860→        {lines.map((line, i) =>
861→          renderLine(line, i, isTyping && i === lines.length - 1)
862→        )}
863→
864→        {/* Input prompt */}
865→        {bootComplete && !isTyping && (
866→          <div className="mt-3">
867→            <div className="text-[#3f3f46] text-sm select-none overflow-hidden whitespace-nowrap">
868→              {boxLine}
869→            </div>
870→            <div className="flex items-center py-1.5">
871→              <span className="text-[#10b981] text-sm">❯&nbsp;</span>
872→              <div className="flex-1 relative">
873→                <input
874→                  ref={inputRef}
875→                  type="text"
876→                  value={inputValue}
877→                  onChange={(e) => setInputValue(e.target.value)}
878→                  onKeyDown={(e) => {
879→                    if (e.key === "Enter") {
880→                      handleSubmit();
881→                    }
882→                  }}
883→                  disabled={isLoading}
884→                  className={`w-full bg-transparent font-mono text-sm outline-none caret-transparent disabled:opacity-50 ${
885→                    inputValue.startsWith("/") && inputValue.toLowerCase().trim() in SLASH_COMMANDS
886→                      ? "text-[#10b981]"
887→                      : "text-[#fafafa]"
888→                  }`}
889→                  spellCheck={false}
890→                  autoComplete="off"
891→                  placeholder="Ask anything or /help..."
892→                  aria-label="Terminal input"
893→                />
894→                {/* Block cursor */}
895→                <span
896→                  className="absolute top-1/2 -translate-y-1/2 w-[9px] h-[18px] bg-[#10b981] pointer-events-none"
897→                  style={{
898→                    left: `${inputValue.length}ch`,
899→                    animation: "terminal-blink 1s step-end infinite",
900→                  }}
901→                />
902→              </div>
903→            </div>
904→            <div className="text-[#3f3f46] text-sm select-none overflow-hidden whitespace-nowrap">
905→              {boxLine}
906→            </div>
907→          </div>
908→        )}
909→      </div>
910→
911→      {/* Status bar */}
912→      <div className="flex items-center justify-between px-4 py-1.5 border-t border-[#27272a] text-[10px] select-none">
913→        <span>
914→          <span className="text-[#10b981]">cameronkeith</span>
