// Track whether we're inside a <think> block to filter reasoning
let insideThink = false;
let thinkBuffer = "";

for await (const event of eventStream) {
  // Stream text content from the LLM (skip reasoning/thinking tokens)
  if (event.event === "on_chat_model_stream") {
    const chunk = event.data.chunk;
    // Skip chunks that are reasoning/thinking content
    if (chunk?.additional_kwargs?.reasoning_content) continue;
    let content = chunk?.content;
    if (content && typeof content === "string") {
      // Filter out <think>...</think> blocks (may span multiple chunks)
      if (insideThink) {
        const closeIdx = content.indexOf("</think>");
        if (closeIdx === -1) {
          // Still inside think block, skip entire chunk
          continue;
        }
        // Think block ends in this chunk
        insideThink = false;
        content = content.slice(closeIdx + "</think>".length);
        if (!content) continue;
      }

      // Check for think tags starting in this chunk
      const openIdx = content.indexOf("<think>");
      if (openIdx !== -1) {
        const before = content.slice(0, openIdx);
        const after = content.slice(openIdx + "<think>".length);
        const closeIdx = after.indexOf("</think>");
        if (closeIdx !== -1) {
          // Think block opens and closes in same chunk
          content = before + after.slice(closeIdx + "</think>".length);
        } else {
          // Think block opens but doesn't close
          insideThink = true;
          content = before;
        }
        if (!content) continue;
      }

      // Also handle partial tag at end of chunk (e.g. "<thi")
      if (content.includes("<") && !content.includes(">")) {
        const lastOpen = content.lastIndexOf("<");
        const partial = content.slice(lastOpen);
        if ("<think>".startsWith(partial)) {
          thinkBuffer = partial;
          content = content.slice(0, lastOpen);
          if (!content) continue;
        }
      } else if (thinkBuffer) {
        content = thinkBuffer + content;
        thinkBuffer = "";
        // Re-check for complete think tag
        if (content.includes("<think>")) {
          const idx = content.indexOf("<think>");
          insideThink = true;
          content = content.slice(0, idx);
          if (!content) continue;
        }
      }

      controller.enqueue(
        encoder.encode(
          JSON.stringify({ type: "text", content }) + "\n"
        )
      );
    }
  }

