import { NextRequest, NextResponse } from "next/server";
import { createAgent } from "@/lib/agent/graph";
import { HumanMessage, AIMessage } from "@langchain/core/messages";

export async function POST(request: NextRequest) {
  if (!process.env.XAI_API_KEY) {
    return NextResponse.json(
      { error: "XAI_API_KEY not configured" },
      { status: 500 }
    );
  }

  let body: { messages: { role: string; content: string }[] };
  try {
    body = await request.json();
  } catch {
    return NextResponse.json({ error: "Invalid JSON" }, { status: 400 });
  }

  if (!body.messages || !Array.isArray(body.messages)) {
    return NextResponse.json(
      { error: "messages array required" },
      { status: 400 }
    );
  }

  const agent = createAgent();

  // Convert client messages to LangChain format
  const langchainMessages = body.messages.map(
    (m: { role: string; content: string }) => {
      if (m.role === "user") {
        return new HumanMessage(m.content);
      }
      return new AIMessage(m.content);
    }
  );

  const encoder = new TextEncoder();

  const stream = new ReadableStream({
    async start(controller) {
      try {
        let navigateRoute: string | null = null;
        let openResume = false;

        const eventStream = agent.streamEvents(
          { messages: langchainMessages },
          { version: "v2" }
        );

        // Track whether we're inside a <think> block to filter reasoning
        let insideThink = false;
        let thinkBuffer = "";

        for await (const event of eventStream) {
          // Stream text content from the LLM (skip reasoning/thinking tokens)
          if (event.event === "on_chat_model_stream") {
            const chunk = event.data.chunk;
            // Skip chunks that are reasoning/thinking content
            if (chunk?.additional_kwargs?.reasoning_content) continue;
            let content = chunk?.content;
            if (content && typeof content === "string") {
              // Filter out <think>...</think> blocks (may span multiple chunks)
              if (insideThink) {
                const closeIdx = content.indexOf("</think>");
                if (closeIdx === -1) {
                  // Still inside think block, skip entire chunk
                  continue;
                }
                // Think block ends in this chunk
                insideThink = false;
                content = content.slice(closeIdx + "</think>".length);
                if (!content) continue;
              }

              // Check for think tags starting in this chunk
              const openIdx = content.indexOf("<think>");
              if (openIdx !== -1) {
                const before = content.slice(0, openIdx);
                const after = content.slice(openIdx + "<think>".length);
                const closeIdx = after.indexOf("</think>");
                if (closeIdx !== -1) {
                  // Think block opens and closes in same chunk
                  content = before + after.slice(closeIdx + "</think>".length);
                } else {
                  // Think block opens but doesn't close
                  insideThink = true;
                  content = before;
                }
                if (!content) continue;
              }

              // Also handle partial tag at end of chunk (e.g. "<thi")
              if (content.includes("<") && !content.includes(">")) {
                const lastOpen = content.lastIndexOf("<");
                const partial = content.slice(lastOpen);
                if ("<think>".startsWith(partial)) {
                  thinkBuffer = partial;
                  content = content.slice(0, lastOpen);
                  if (!content) continue;
                }
              } else if (thinkBuffer) {
                content = thinkBuffer + content;
                thinkBuffer = "";
                // Re-check for complete think tag
                if (content.includes("<think>")) {
                  const idx = content.indexOf("<think>");
                  insideThink = true;
                  content = content.slice(0, idx);
                  if (!content) continue;
                }
              }

              controller.enqueue(
                encoder.encode(
                  JSON.stringify({ type: "text", content }) + "\n"
                )
              );
            }
          }

          // Capture tool actions
          if (event.event === "on_tool_end") {
            try {
              const output =
                typeof event.data.output === "string"
                  ? event.data.output
                  : event.data.output?.content
                    ? String(event.data.output.content)
                    : String(event.data.output);
              const parsed = JSON.parse(output);
              if (parsed.action === "navigate") {
                navigateRoute = parsed.route;
              } else if (parsed.action === "open_resume") {
                openResume = true;
              }
            } catch {
              // Tool output wasn't parseable - ignore
            }
          }
        }

        // Send action events after text is complete
        if (navigateRoute) {
          controller.enqueue(
            encoder.encode(
              JSON.stringify({ type: "navigate", route: navigateRoute }) + "\n"
            )
          );
        }
        if (openResume) {
          controller.enqueue(
            encoder.encode(
              JSON.stringify({ type: "open_resume", url: "/cameron-keith-resume.pdf" }) + "\n"
            )
          );
        }

        controller.enqueue(
          encoder.encode(JSON.stringify({ type: "done" }) + "\n")
        );
      } catch {
        controller.enqueue(
          encoder.encode(
            JSON.stringify({
              type: "error",
              message: "Something went wrong. Please try again.",
            }) + "\n"
          )
        );
      } finally {
        controller.close();
      }
    },
  });

  return new Response(stream, {
    headers: {
      "Content-Type": "text/plain; charset=utf-8",
      "Cache-Control": "no-cache",
    },
  });
}

